import fs from 'fs/promises';
import path from 'path';
import { prisma } from './prisma';

const LOCALES_DIR = path.join(process.cwd(), 'src/locales');

interface TranslationData {
  [key: string]: string | TranslationData;
}

/**
 * Flatten nested translation object to dot notation keys
 */
function flattenTranslations(obj: TranslationData, prefix = ''): Record<string, string> {
  const flattened: Record<string, string> = {};
  
  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    
    if (typeof value === 'string') {
      flattened[newKey] = value;
    } else if (typeof value === 'object' && value !== null) {
      Object.assign(flattened, flattenTranslations(value, newKey));
    }
  }
  
  return flattened;
}

/**
 * Convert flat keys back to nested object structure
 */
function unflattenTranslations(flat: Record<string, string>): TranslationData {
  const nested: TranslationData = {};
  
  for (const [key, value] of Object.entries(flat)) {
    const keys = key.split('.');
    let current = nested;
    
    for (let i = 0; i < keys.length - 1; i++) {
      const k = keys[i];
      if (!(k in current)) {
        current[k] = {};
      }
      current = current[k] as TranslationData;
    }
    
    current[keys[keys.length - 1]] = value;
  }
  
  return nested;
}

/**
 * Import translations from JSON files to database
 */
export async function importTranslationsFromFiles(): Promise<void> {
  const languages = ['en', 'ar'];
  
  for (const lang of languages) {
    const filePath = path.join(LOCALES_DIR, lang, 'common.json');
    
    try {
      const fileContent = await fs.readFile(filePath, 'utf-8');
      const translations = JSON.parse(fileContent);
      const flattened = flattenTranslations(translations);
      
      // Clear existing translations for this language
      await prisma.translation.deleteMany({
        where: { language: lang },
      });
      
      // Insert new translations
      const translationRecords = Object.entries(flattened).map(([key, value]) => {
        const namespace = key.split('.')[0]; // First part as namespace
        return {
          key,
          language: lang,
          value,
          namespace,
        };
      });
      
      await prisma.translation.createMany({
        data: translationRecords,
      });
      
      console.log(`✅ Imported ${translationRecords.length} translations for ${lang}`);
    } catch (error) {
      console.error(`❌ Failed to import translations for ${lang}:`, error);
    }
  }
}

/**
 * Export translations from database to JSON files
 */
export async function exportTranslationsToFiles(): Promise<void> {
  const languages = ['en', 'ar'];
  
  for (const lang of languages) {
    try {
      const translations = await prisma.translation.findMany({
        where: { language: lang },
        select: { key: true, value: true },
      });
      
      const flat = translations.reduce((acc, t) => {
        acc[t.key] = t.value;
        return acc;
      }, {} as Record<string, string>);
      
      const nested = unflattenTranslations(flat);
      
      const filePath = path.join(LOCALES_DIR, lang, 'common.json');
      await fs.writeFile(filePath, JSON.stringify(nested, null, 2), 'utf-8');
      
      console.log(`✅ Exported ${translations.length} translations to ${filePath}`);
    } catch (error) {
      console.error(`❌ Failed to export translations for ${lang}:`, error);
    }
  }
}

/**
 * Get all translations from database grouped by language
 */
export async function getAllTranslations(): Promise<Record<string, Record<string, string>>> {
  const translations = await prisma.translation.findMany({
    orderBy: [{ language: 'asc' }, { key: 'asc' }],
  });
  
  const grouped: Record<string, Record<string, string>> = {};
  
  for (const translation of translations) {
    if (!grouped[translation.language]) {
      grouped[translation.language] = {};
    }
    grouped[translation.language][translation.key] = translation.value;
  }
  
  return grouped;
}